import SwiftUI

/// The menu-bar duck glyph: the provided single-path silhouette, filled white,
/// scaled to fit while preserving its aspect ratio.
struct DuckIconView: View {
    // viewBox 238 × 231 from the source SVG.
    private static let viewBox = CGSize(width: 238, height: 231)
    private static let duckPath = SVGPath.path(from: duckPathData)

    var body: some View {
        Canvas { ctx, size in
            let scale = min(size.width / Self.viewBox.width, size.height / Self.viewBox.height)
            let dx = (size.width - Self.viewBox.width * scale) / 2
            let dy = (size.height - Self.viewBox.height * scale) / 2
            let transform = CGAffineTransform(translationX: dx, y: dy).scaledBy(x: scale, y: scale)
            ctx.fill(Self.duckPath.applying(transform), with: .color(.white))
        }
        .frame(width: 18, height: 17.5)   // ~238:231 aspect
    }
}

